e: 19/4/2026 12:58:08 ******/SET ANSI_NULLS ONGOSET QUOTED_IDENTIFIER ONGOCREATE PROCEDURE [dbo].[InsertarBitacora]    @usuario INT,    @fecha DATETIME,    @actividad VARCHAR(50),    @criticidad INTASBEGIN    DECLARE @id int    SET @id = (SELECT ISNULL(MAX(BITACORA_ID), 0) + 1 FROM BITACORA)    INSERT INTO Bitacora (BITACORA_ID, USUARIO_ID, Fecha, Actividad, CRITICIDAD_ID)    VALUES (@id, @usuario, @fecha, @actividad, @criticidad)ENDGO/****** Object:  StoredProcedure [dbo].[ListarBitacoraFiltrado]    Script Date: 19/4/2026 12:58:08 ******/SET ANSI_NULLS ONGOSET QUOTED_IDENTIFIER ONGOCREATE PROCEDURE [dbo].[ListarBitacoraFiltrado]    @usuarioIds NVARCHAR(MAX) = NULL,    @fechaInicio DATETIME = NULL,    @fechaFin DATETIME = NULL,    @actividades NVARCHAR(MAX) = NULL,    @criticidades NVARCHAR(MAX) = NULLASBEGIN    SELECT BITACORA_ID, USUARIO_ID, Fecha, Actividad, CRITICIDAD_ID    FROM Bitacora    WHERE         (@usuarioIds IS NULL OR USUARIO_ID IN (SELECT value FROM STRING_SPLIT(@usuarioIds, ',')))        AND (@fechaInicio IS NULL OR Fecha >= @fechaInicio)        AND (@fechaFin IS NULL OR Fecha <= @fechaFin)        AND (@actividades IS NULL OR Actividad IN (SELECT value FROM STRING_SPLIT(@actividades, ',')))        AND (@criticidades IS NULL OR CRITICIDAD_ID IN (SELECT value FROM STRING_SPLIT(@criticidades, ',')))    ORDER BY Fecha DESCENDGO/****** Object:  StoredProcedure [dbo].[ListarUsuario]    Script Date: 19/4/2026 12:58:08 ******/SET ANSI_NULLS ONGOSET QUOTED_IDENTIFIER ONGOCREATE PROC [dbo].[ListarUsuario]ASBEGINSELECT * FROM USUARIOENDGO/****** Object:  StoredProcedure [dbo].[ReestablecerIntentos]    Script Date: 19/4/2026 12:58:08 ******/SET ANSI_NULLS ONGOSET QUOTED_IDENTIFIER ONGOCREATE PROCEDURE [dbo].[ReestablecerIntentos]    @id intASBEGIN    UPDATE USUARIO    SET INTENTOS = 0    WHERE USUARIO_ID = @idENDGO/****** Object:  StoredProcedure [dbo].[TraerPass]    Script Date: 19/4/2026 12:58:08 ******/SET ANSI_NULLS ONGOSET QUOTED_IDENTIFIER ONGOCREATE PROC [dbo].[TraerPass]    @user varchar(50)ASBEGIN    SET NOCOUNT ON;    SELECT PASS_HASH, SALT    FROM USUARIO    WHERE USUARIO = @user      AND BORRADO = 0;ENDGOUSE [master]GOALTER DATABASE [CAMPO] SET  READ_WRITE GO 